// Isolates the webgpu_host create-path (where the double-lock lived): a tight
// loop of device.createBuffer. Measures the binding's own CPU cost, not the GPU.
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();
const N = 2500;
const t0 = Date.now();
for (let i = 0; i < N; i++) {
  device.createBuffer({ size: 256, usage: GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST });
}
const ms = Date.now() - t0;
console.log('__RESULT__ ' + JSON.stringify({ n: N, ms, perCallUs: Math.round((ms * 1000) / N) }));
